# Snyk Studio Recipes — self-extracting installer (generated; do not edit)
$ErrorActionPreference = "Stop"

function Main {
    param(
        [Parameter(ValueFromRemainingArguments = $true)]
        [string[]]$ForwardArgs
    )
    Ensure-Uv -ForwardArgs $ForwardArgs

    $scriptPath = $PSCommandPath
    if ([string]::IsNullOrWhiteSpace($scriptPath)) {
        $scriptPath = $MyInvocation.PSCommandPath
    }
    if ([string]::IsNullOrWhiteSpace($scriptPath)) {
        throw "Unable to determine script path for embedded payload extraction."
    }
    $workDir = Join-Path ([System.IO.Path]::GetTempPath()) ("snyk-studio-install-" + [Guid]::NewGuid().ToString("N"))
    New-Item -ItemType Directory -Path $workDir -Force | Out-Null
    # Env name is a build-time placeholder; build_installer rewrites it to SNYK_STUDIO_BUNDLE_ROOT.
    $env:SNYK_STUDIO_BUNDLE_ROOT = $workDir
    $bytes = Get-EmbeddedPayloadBytes -ScriptPath $scriptPath -Marker '__SNYK_STUDIO_BUNDLE_B64__'
    Expand-BundleZip -BundleBytes $bytes -DestinationDir $workDir
    $installer = Join-Path $workDir "snyk-studio-installer.py"
    try {
        $uvLocalBin = Join-Path $env:USERPROFILE ".local\bin"
        if (Test-Path -LiteralPath $uvLocalBin) {
            $env:Path = "$uvLocalBin$([System.IO.Path]::PathSeparator)$env:Path"
        }
        & uv run $installer @ForwardArgs
        exit $LASTEXITCODE
    } finally {
        Remove-Item -LiteralPath $workDir -Recurse -Force -ErrorAction SilentlyContinue
    }
}

function Ensure-Uv {
    param([string[]]$ForwardArgs)

    $autoYes = $false
    if ($null -ne $ForwardArgs) {
        foreach ($a in $ForwardArgs) {
            if ($a -eq "-y" -or $a -eq "--yes") {
                $autoYes = $true
                break
            }
        }
    }

    $uvLocalBin = Join-Path $env:USERPROFILE ".local\bin"
    if (Test-Path -LiteralPath $uvLocalBin) {
        $env:Path = "$uvLocalBin$([System.IO.Path]::PathSeparator)$env:Path"
    }

    if (Get-Command uv -ErrorAction SilentlyContinue) {
        $ver = (& uv --version 2>$null | Select-Object -First 1)
        Write-Host "  OK uv $ver"
        return
    }

    Write-Host "  WARNING uv not found" -ForegroundColor Yellow
    Write-Host "    Install with: irm https://astral.sh/uv/install.ps1 | iex"

    if (-not $autoYes) {
        # Only prompt on an interactive console; if stdin is redirected (pipe/file)
        # Read-Host would block or fail in an automated run, so fail fast.
        if ([System.Console]::IsInputRedirected) {
            Write-Error "  uv is required; re-run with -y to install it without prompting."
            exit 1
        }
        $reply = (Read-Host "`n  Install uv now? (y/n)").Trim().ToLowerInvariant()
        if ($reply -ne "y" -and $reply -ne "yes") {
            Write-Error "  Cancelled: uv is required to run this installer."
            exit 1
        }
    }

    Invoke-Expression (Invoke-RestMethod -Uri 'https://astral.sh/uv/install.ps1')

    if (Test-Path -LiteralPath $uvLocalBin) {
        $env:Path = "$uvLocalBin$([System.IO.Path]::PathSeparator)$env:Path"
    }
    if (-not (Get-Command uv -ErrorAction SilentlyContinue)) {
        throw "uv was installed but is not on PATH. Add $uvLocalBin to PATH and retry."
    }
}

function Get-EmbeddedPayloadBytes {
    param(
        [Parameter(Mandatory = $true)][string]$ScriptPath,
        [Parameter(Mandatory = $true)][string]$Marker
    )

    $allLines = Get-Content -LiteralPath $ScriptPath -Encoding UTF8
    $markerLine = -1
    for ($i = 0; $i -lt $allLines.Count; $i++) {
        if ($allLines[$i] -eq $Marker) { $markerLine = $i; break }
    }
    if ($markerLine -lt 0) { throw "Missing bundle marker in script." }

    $payloadLines = @()
    for ($j = $markerLine + 1; $j -lt $allLines.Count; $j++) {
        $line = $allLines[$j]
        if ($line.Trim() -eq '#>') { break }
        $payloadLines += $line
    }

    $b64 = ($payloadLines -join '').Replace(' ', '')
    # Keep the byte array as a single object (don't enumerate into Object[]).
    return ,([Convert]::FromBase64String($b64))
}

function Expand-BundleZip {
    param(
        [Parameter(Mandatory = $true)][byte[]]$BundleBytes,
        [Parameter(Mandatory = $true)][string]$DestinationDir
    )

    # The built-in Expand-Archive does not operate on memory streams so we 
    # use System.IO.Compression and iterate over the zip ourselves 
    Add-Type -AssemblyName System.IO.Compression
    Add-Type -AssemblyName System.IO.Compression.FileSystem

    $ms = New-Object System.IO.MemoryStream(,[byte[]]$BundleBytes)
    $zip = New-Object System.IO.Compression.ZipArchive($ms, [System.IO.Compression.ZipArchiveMode]::Read)
    try {
        $rootFull = [System.IO.Path]::GetFullPath($DestinationDir)
        if (-not $rootFull.EndsWith([System.IO.Path]::DirectorySeparatorChar)) {
            $rootFull += [System.IO.Path]::DirectorySeparatorChar
        }
        foreach ($entry in $zip.Entries) {
            $name = $entry.FullName.Replace('/', [System.IO.Path]::DirectorySeparatorChar)
            if ($name.EndsWith([System.IO.Path]::DirectorySeparatorChar)) {
                $dirPath = [System.IO.Path]::GetFullPath((Join-Path $DestinationDir $name.TrimEnd([System.IO.Path]::DirectorySeparatorChar)))
                if (-not $dirPath.StartsWith($rootFull, [System.StringComparison]::OrdinalIgnoreCase)) {
                    throw "Refusing unsafe zip path: $($entry.FullName)"
                }
                New-Item -ItemType Directory -Path $dirPath -Force | Out-Null
                continue
            }
            $destPath = [System.IO.Path]::GetFullPath((Join-Path $DestinationDir $name))
            if (-not $destPath.StartsWith($rootFull, [System.StringComparison]::OrdinalIgnoreCase)) {
                throw "Refusing unsafe zip path: $($entry.FullName)"
            }
            $parent = [System.IO.Path]::GetDirectoryName($destPath)
            if (-not [string]::IsNullOrEmpty($parent)) {
                New-Item -ItemType Directory -Path $parent -Force | Out-Null
            }
            $in = $entry.Open()
            try {
                $out = New-Object System.IO.FileStream($destPath, [System.IO.FileMode]::Create, [System.IO.FileAccess]::Write)
                try {
                    $in.CopyTo($out)
                } finally {
                    $out.Close()
                }
            } finally {
                $in.Close()
            }
        }
    } finally {
        $zip.Dispose()
        $ms.Close()
    }
}

